42	impl AppState {
43	    fn new() -> Self {
44	        Self {
45	            messages: Vec::new(),
46	            input: String::new(),
47	            status_agent: "Rei".into(),
48	            status_model: String::new(),
49	            status_tokens: 0,
50	            status_cost: 0.0,
51	            status_text: String::new(),
52	            scroll_offset: 0,
53	            ws_tx: None,
54	            should_quit: false,
55	            agent_id: None,
56	            project: None,
57	        }
58	    }
59	
60	    fn push_user(&mut self, text: &str) {
61	        self.messages.push(ChatLine {
62	            role: "You".into(),
63	            text: text.to_string(),
64	            style: Style::default().fg(Color::Cyan),
65	        });
66	    }
67	
68	    fn push_assistant_start(&mut self) {
69	        self.messages.push(ChatLine {
70	            role: "Rei".into(),
71	            text: String::new(),
72	            style: Style::default().fg(Color::Green),
73	        });
74	    }
75	
76	    fn append_assistant_text(&mut self, delta: &str) {
77	        if let Some(last) = self.messages.last_mut()
78	            && last.role == "Rei"
79	        {
80	            last.text.push_str(delta);
81	            return;
82	        }
83	        // No active assistant line — create one.
84	        self.push_assistant_start();
85	        if let Some(last) = self.messages.last_mut() {
86	            last.text.push_str(delta);
87	        }
88	    }
89	
90	    fn push_system(&mut self, text: String, style: Style) {
91	        self.messages.push(ChatLine {
92	            role: String::new(),
93	            text,
94	            style,
95	        });
96	    }
97	
98	    /// Update an existing tool line (matched by tool_use_id prefix) in place.
99	    fn update_tool_line(&mut self, tool_name: &str, replacement: String, style: Style) {
100	        // Walk backwards to find the matching tool start line.
101	        for line in self.messages.iter_mut().rev() {
102	            if line.text.contains(&format!("\u{2699} {tool_name}")) {
103	                line.text = replacement;
104	                line.style = style;
105	                return;
106	            }
107	        }
108	        // Fallback: just append.
109	        self.push_system(replacement, style);
110	    }
111	}
