113	// ---------------------------------------------------------------------------
114	// WebSocket background thread
115	// ---------------------------------------------------------------------------
116	
117	enum WsCommand {
118	    Send(String),
119	    Quit,
120	}
121	
122	fn spawn_ws_thread(
123	    url: String,
124	    cmd_rx: mpsc::Receiver<WsCommand>,
125	    event_tx: mpsc::Sender<ChatStreamEvent>,
126	) -> std::thread::JoinHandle<()> {
127	    std::thread::spawn(move || {
128	        use tungstenite::Message;
129	
130	        let mut ws = match tungstenite::connect(&url) {
131	            Ok((ws, _)) => ws,
132	            Err(e) => {
133	                let _ = event_tx.send(ChatStreamEvent::Error {
134	                    message: format!("WebSocket connect to {url} failed: {e}"),
135	                    recoverable: false,
136	                });
137	                return;
138	            }
139	        };
140	
141	        // Make the underlying TCP stream non-blocking so we can interleave
142	        // send commands with incoming reads.
143	        if let tungstenite::stream::MaybeTlsStream::Plain(tcp) = ws.get_ref() {
144	            tcp.set_nonblocking(true).ok();
145	        }
146	
147	        loop {
148	            // Check for outbound commands (non-blocking).
149	            match cmd_rx.try_recv() {
150	                Ok(WsCommand::Send(text)) => {
151	                    // Switch to blocking briefly for the send.
152	                    if let tungstenite::stream::MaybeTlsStream::Plain(tcp) = ws.get_ref() {
153	                        tcp.set_nonblocking(false).ok();
154	                    }
155	                    if ws.send(Message::Text(text.into())).is_err() {
156	                        break;
157	                    }
158	                    if let tungstenite::stream::MaybeTlsStream::Plain(tcp) = ws.get_ref() {
159	                        tcp.set_nonblocking(true).ok();
160	                    }
161	                }
162	                Ok(WsCommand::Quit) => {
163	                    if let tungstenite::stream::MaybeTlsStream::Plain(tcp) = ws.get_ref() {
164	                        tcp.set_nonblocking(false).ok();
165	                    }
166	                    let _ = ws.close(None);
167	                    break;
168	                }
169	                Err(mpsc::TryRecvError::Disconnected) => break,
170	                Err(mpsc::TryRecvError::Empty) => {}
171	            }
172	
173	            // Try to read an incoming message (non-blocking).
174	            match ws.read() {
175	                Ok(Message::Text(text)) => {
176	                    if let Ok(evt) = serde_json::from_str::<ChatStreamEvent>(&text)
177	                        && event_tx.send(evt).is_err()
178	                    {
179	                        break;
180	                    }
181	                }
182	                Ok(Message::Close(_)) => break,
183	                Err(tungstenite::Error::Io(ref e)) if e.kind() == io::ErrorKind::WouldBlock => {
184	                    // Nothing available — sleep briefly so we don't spin.
185	                    std::thread::sleep(Duration::from_millis(10));
186	                }
187	                Err(_) => break,
188	                _ => {} // Ping/Pong/Binary — ignore
189	            }
190	        }
191	    })
192	}
