195	// TUI rendering
196	// ---------------------------------------------------------------------------
197	
198	fn draw(frame: &mut Frame, state: &AppState) {
199	    let chunks = Layout::default()
200	        .direction(Direction::Vertical)
201	        .constraints([
202	            Constraint::Min(1),    // messages
203	            Constraint::Length(1), // status bar
204	            Constraint::Length(3), // input
205	        ])
206	        .split(frame.area());
207	
208	    draw_messages(frame, chunks[0], state);
209	    draw_status(frame, chunks[1], state);
210	    draw_input(frame, chunks[2], state);
211	}
212	
213	fn draw_messages(frame: &mut Frame, area: Rect, state: &AppState) {
214	    let mut lines: Vec<Line> = Vec::new();
215	
216	    for msg in &state.messages {
217	        let prefix = if msg.role.is_empty() {
218	            "  ".to_string()
219	        } else {
220	            format!("{}: ", msg.role)
221	        };
222	
223	        // Split text into wrapped display lines.
224	        let full = format!("{prefix}{}", msg.text);
225	        let width = area.width.saturating_sub(2) as usize; // account for block border
226	        if width == 0 {
227	            lines.push(Line::from(Span::styled(full, msg.style)));
228	            continue;
229	        }
230	
231	        for chunk in textwrap(full.as_str(), width) {
232	            lines.push(Line::from(Span::styled(chunk, msg.style)));
233	        }
234	    }
235	
236	    // Auto-scroll: show the tail.
237	    let visible = area.height.saturating_sub(2) as usize; // block borders
238	    let scroll = if lines.len() > visible {
239	        (lines.len() - visible) as u16
240	    } else {
241	        0
242	    };
243	
244	    let paragraph = Paragraph::new(lines)
245	        .block(Block::default().borders(Borders::ALL).title(" Chat "))
246	        .scroll((scroll, 0))
247	        .wrap(Wrap { trim: false });
248	
249	    frame.render_widget(paragraph, area);
250	}
251	
252	fn draw_status(frame: &mut Frame, area: Rect, state: &AppState) {
253	    let tokens_fmt = format_number(state.status_tokens);
254	    let cost_fmt = format!("${:.2}", state.status_cost);
255	
256	    let model_display = if state.status_model.is_empty() {
257	        String::new()
258	    } else {
259	        format!(" | {}", state.status_model)
260	    };
261	
262	    let extra = if state.status_text.is_empty() {
263	        String::new()
264	    } else {
265	        format!(" | {}", state.status_text)
266	    };
267	
268	    let text = format!(
269	        "\u{25cf} {}{} | {} tokens | {}{}",
270	        state.status_agent, model_display, tokens_fmt, cost_fmt, extra,
271	    );
272	
273	    let bar = Paragraph::new(text).style(Style::default().bg(Color::DarkGray).fg(Color::White));
274	    frame.render_widget(bar, area);
275	}
276	
277	fn draw_input(frame: &mut Frame, area: Rect, state: &AppState) {
278	    let display = format!("> {}", state.input);
279	    let input = Paragraph::new(display)
280	        .block(Block::default().borders(Borders::ALL).title(" Input "))
281	        .style(Style::default().fg(Color::Yellow));
282	    frame.render_widget(input, area);
283	
284	    // Place cursor after the input text.
285	    let cursor_x = area.x + 1 + 2 + state.input.len() as u16; // border + "> " prefix
286	    let cursor_y = area.y + 1; // inside border
287	    frame.set_cursor_position((
288	        cursor_x.min(area.x + area.width.saturating_sub(2)),
289	        cursor_y,
290	    ));
291	}
