296	
297	fn textwrap(s: &str, width: usize) -> Vec<String> {
298	    if width == 0 {
299	        return vec![s.to_string()];
300	    }
301	    let mut result = Vec::new();
302	    for line in s.split('\n') {
303	        if line.is_empty() {
304	            result.push(String::new());
305	            continue;
306	        }
307	        let chars: Vec<char> = line.chars().collect();
308	        for chunk in chars.chunks(width) {
309	            result.push(chunk.iter().collect());
310	        }
311	    }
312	    result
313	}
314	
315	fn format_number(n: u32) -> String {
316	    let s = n.to_string();
317	    let mut result = String::new();
318	    for (i, c) in s.chars().rev().enumerate() {
319	        if i > 0 && i % 3 == 0 {
320	            result.push(',');
321	        }
322	        result.push(c);
323	    }
324	    result.chars().rev().collect()
325	}
