331	fn process_ws_event(state: &mut AppState, evt: ChatStreamEvent) {
332	    match evt {
333	        ChatStreamEvent::TextDelta { text } => {
334	            state.append_assistant_text(&text);
335	        }
336	        ChatStreamEvent::ToolStart { tool_name, .. } => {
337	            state.push_system(
338	                format!("  \u{2699} {tool_name}..."),
339	                Style::default().fg(Color::DarkGray),
340	            );
341	        }
342	        ChatStreamEvent::ToolComplete {
343	            tool_name,
344	            duration_ms,
345	            success,
346	            ..
347	        } => {
348	            let icon = if success { "\u{2713}" } else { "\u{2717}" };
349	            let style = if success {
350	                Style::default().fg(Color::DarkGray)
351	            } else {
352	                Style::default().fg(Color::Red)
353	            };
354	            state.update_tool_line(
355	                &tool_name,
356	                format!("  {icon} {tool_name} ({duration_ms}ms)"),
357	                style,
358	            );
359	        }
360	        ChatStreamEvent::TurnStart { turn, model } => {
361	            state.push_system(
362	                format!("  \u{21bb} Turn {turn}..."),
363	                Style::default().fg(Color::DarkGray),
364	            );
365	            state.status_model = model;
366	            // Start a new assistant message for this turn's text.
367	            state.push_assistant_start();
368	        }
369	        ChatStreamEvent::TurnComplete {
370	            prompt_tokens,
371	            completion_tokens,
372	            ..
373	        } => {
374	            state.status_tokens = prompt_tokens + completion_tokens;
375	        }
376	        ChatStreamEvent::Complete {
377	            total_prompt_tokens,
378	            total_completion_tokens,
379	            cost_usd,
380	            ..
381	        } => {
382	            state.status_tokens = total_prompt_tokens + total_completion_tokens;
383	            state.status_cost = cost_usd;
384	            state.status_text.clear();
385	        }
386	        ChatStreamEvent::Status { message } => {
387	            state.status_text = message;
388	        }
389	        ChatStreamEvent::Error { message, .. } => {
390	            state.push_system(
391	                format!("  ERROR: {message}"),
392	                Style::default().fg(Color::Red),
393	            );
394	        }
395	        ChatStreamEvent::DelegateStart {
396	            worker_name,
397	            task_subject,
398	        } => {
399	            state.push_system(
400	                format!("  \u{2192} Delegating to {worker_name}: {task_subject}"),
401	                Style::default().fg(Color::Magenta),
402	            );
403	        }
404	        ChatStreamEvent::DelegateComplete {
405	            worker_name,
406	            outcome,
407	        } => {
408	            state.push_system(
409	                format!("  \u{2190} {worker_name}: {outcome}"),
410	                Style::default().fg(Color::Magenta),
411	            );
412	        }
413	        ChatStreamEvent::MemoryActivity {
414	            action,
415	            key,
416	            preview,
417	        } => {
418	            let icon = if action == "recalled" {
419	                "\u{1f4d6}"
420	            } else {
421	                "\u{1f4be}"
422	            };
423	            state.push_system(
424	                format!("  {icon} {action} [{key}]: {}", truncate(&preview, 60)),
425	                Style::default().fg(Color::DarkGray),
426	            );
427	        }
428	        ChatStreamEvent::Compacted {
429	            original_messages,
430	            remaining_messages,
431	            ..
432	        } => {
433	            state.push_system(
434	                format!(
435	                    "  \u{267b} Compacted {original_messages} \u{2192} {remaining_messages} messages"
436	                ),
437	                Style::default().fg(Color::DarkGray),
438	            );
439	        }
440	        ChatStreamEvent::ToolProgress { .. } => {
441	            // Silently ignore progress deltas for now.
442	        }
443	    }
444	}
