458	/// Terminal chat interface using ratatui + crossterm + tungstenite.
459	pub(crate) async fn cmd_chat_tui(
460	    config_path: &Option<PathBuf>,
461	    agent_name: Option<&str>,
462	    project: Option<&str>,
463	) -> Result<()> {
464	    let (config, _) = load_config(config_path)?;
465	    let data_dir = config.data_dir();
466	
467	    // Resolve the persistent agent to chat with.
468	    let registry = sigil_orchestrator::agent_registry::AgentRegistry::open(&data_dir)?;
469	    let agent = if let Some(name) = agent_name {
470	        registry.get_active_by_name(name).await?
471	    } else {
472	        registry.default_for_project(project).await?
473	    };
474	
475	    let (agent_display, agent_id) = match &agent {
476	        Some(a) => (
477	            a.display_name.as_deref().unwrap_or(&a.name).to_string(),
478	            Some(a.id.clone()),
479	        ),
480	        None => (
481	            config
482	                .leader_agent()
483	                .map(|a| a.name.clone())
484	                .unwrap_or_else(|| "Rei".into()),
485	            None,
486	        ),
487	    };
488	
489	    // Extract port from the bind address (e.g. "0.0.0.0:8400" -> 8400).
490	    let bind = &config.web.bind;
491	    let port = bind
492	        .rsplit(':')
493	        .next()
494	        .and_then(|p| p.parse::<u16>().ok())
495	        .unwrap_or(8400);
496	    let ws_url = format!("ws://127.0.0.1:{port}/api/chat/stream");
497	
498	    // Channels: ws events -> main thread, main thread -> ws commands.
499	    let (event_tx, event_rx) = mpsc::channel::<ChatStreamEvent>();
500	    let (cmd_tx, cmd_rx) = mpsc::channel::<WsCommand>();
501	
502	    let ws_handle = spawn_ws_thread(ws_url, cmd_rx, event_tx);
503	
504	    // Enter terminal raw mode.
505	    terminal::enable_raw_mode()?;
506	    let mut stdout = io::stdout();
507	    crossterm::execute!(
508	        stdout,
509	        terminal::EnterAlternateScreen,
510	        crossterm::cursor::Hide
511	    )?;
512	
513	    let backend = ratatui::backend::CrosstermBackend::new(stdout);
514	    let mut term = ratatui::Terminal::new(backend)?;
515	
516	    let mut state = AppState::new();
517	    state.status_agent = agent_display;
518	    // Store agent_id and project in state for inclusion in WebSocket messages.
519	    state.agent_id = agent_id;
520	    state.project = project.map(|s| s.to_string());
521	
522	    // Main event loop.
523	    let result = run_loop(&mut term, &mut state, &event_rx, &cmd_tx);
524	
525	    // Cleanup: always restore terminal.
526	    let _ = cmd_tx.send(WsCommand::Quit);
527	    terminal::disable_raw_mode()?;
528	    crossterm::execute!(
529	        term.backend_mut(),
530	        terminal::LeaveAlternateScreen,
531	        crossterm::cursor::Show
532	    )?;
533	
534	    // Wait for ws thread to finish (with timeout).
535	    let _ = ws_handle.join();
536	
537	    result
538	}
539	
540	fn run_loop(
541	    term: &mut ratatui::Terminal<ratatui::backend::CrosstermBackend<io::Stdout>>,
542	    state: &mut AppState,
543	    event_rx: &mpsc::Receiver<ChatStreamEvent>,
544	    cmd_tx: &mpsc::Sender<WsCommand>,
545	) -> Result<()> {
546	    loop {
547	        term.draw(|f| draw(f, state))?;
548	
549	        // Drain all pending WebSocket events.
550	        while let Ok(evt) = event_rx.try_recv() {
551	            process_ws_event(state, evt);
552	        }
553	
554	        // Poll crossterm events with 50ms timeout for responsiveness.
555	        if event::poll(Duration::from_millis(50))?
556	            && let Event::Key(key) = event::read()?
557	        {
558	            match key.code {
559	                KeyCode::Esc => {
560	                    state.should_quit = true;
561	                }
562	                KeyCode::Char('c') if key.modifiers.contains(KeyModifiers::CONTROL) => {
563	                    state.should_quit = true;
564	                }
565	                KeyCode::Enter => {
566	                    let text = state.input.trim().to_string();
567	                    if !text.is_empty() {
568	                        state.push_user(&text);
569	                        state.input.clear();
570	
571	                        let mut msg = serde_json::json!({
572	                            "message": text,
573	                        });
574	                        if let Some(ref aid) = state.agent_id {
575	                            msg["agent_id"] = serde_json::json!(aid);
576	                        }
577	                        if let Some(ref p) = state.project {
578	                            msg["project"] = serde_json::json!(p);
579	                        }
580	                        let _ = cmd_tx.send(WsCommand::Send(msg.to_string()));
581	                    }
582	                }
583	                KeyCode::Backspace => {
584	                    state.input.pop();
585	                }
586	                KeyCode::Char(c) => {
587	                    state.input.push(c);
588	                }
589	                _ => {}
590	            }
591	        }
592	
593	        if state.should_quit {
594	            break;
595	        }
596	    }
597	
598	    Ok(())
599	}

