31	
32	    tracing_subscriber::fmt()
33	        .with_env_filter(
34	            tracing_subscriber::EnvFilter::try_from_default_env()
35	                .unwrap_or_else(|_| tracing_subscriber::EnvFilter::new(&cli.log_level)),
36	        )
37	        .with_target(false)
38	        .init();
39	
40	    match cli.command {
41	        None => cmd::chat::cmd_chat(&cli.config).await,
42	        Some(Commands::Run {
43	            prompt,
44	            project,
45	            model,
46	            max_iterations,
47	        }) => {
48	            cmd::run::cmd_run(
49	                &cli.config,
50	                &prompt,
51	                project.as_deref(),
52	                model.as_deref(),
