501	/// Terminal chat interface using ratatui + crossterm + tungstenite.
502	pub(crate) async fn cmd_chat_tui(
503	    config_path: &Option<PathBuf>,
504	    agent_name: Option<&str>,
505	    project: Option<&str>,
506	) -> Result<()> {
507	    let (config, _) = load_config(config_path)?;
508	    let data_dir = config.data_dir();
509	
510	    // Resolve the persistent agent to chat with.
511	    let registry = sigil_orchestrator::agent_registry::AgentRegistry::open(&data_dir)?;
512	    let agent = if let Some(name) = agent_name {
513	        registry.get_active_by_name(name).await?
514	    } else {
515	        registry.default_for_project(project).await?
516	    };
517	
518	    let (agent_display, agent_id) = match &agent {
519	        Some(a) => (
520	            a.display_name.as_deref().unwrap_or(&a.name).to_string(),
521	            Some(a.id.clone()),
522	        ),
523	        None => (
524	            config
525	                .leader_agent()
526	                .map(|a| a.name.clone())
527	                .unwrap_or_else(|| "Rei".into()),
528	            None,
529	        ),
530	    };
531	
532	    // Extract port from the bind address (e.g. "0.0.0.0:8400" -> 8400).
533	    let bind = &config.web.bind;
534	    let port = bind
535	        .rsplit(':')
536	        .next()
537	        .and_then(|p| p.parse::<u16>().ok())
538	        .unwrap_or(8400);
539	    let ws_url = format!("ws://127.0.0.1:{port}/api/chat/stream");
540	
541	    // Channels: ws events -> main thread, main thread -> ws commands.
542	    let (event_tx, event_rx) = mpsc::channel::<ChatStreamEvent>();
543	    let (cmd_tx, cmd_rx) = mpsc::channel::<WsCommand>();
544	
545	    let ws_handle = spawn_ws_thread(ws_url, cmd_rx, event_tx);
546	
547	    // Enter terminal raw mode.
548	    terminal::enable_raw_mode()?;
549	    let mut stdout = io::stdout();
550	    crossterm::execute!(
551	        stdout,
552	        terminal::EnterAlternateScreen,
553	        crossterm::cursor::Hide
554	    )?;
555	
556	    let backend = ratatui::backend::CrosstermBackend::new(stdout);
557	    let mut term = ratatui::Terminal::new(backend)?;
558	
559	    let mut state = AppState::new();
560	    state.status_agent = agent_display;
561	    // Store agent_id and project in state for inclusion in WebSocket messages.
562	    state.agent_id = agent_id;
563	    state.project = project.map(|s| s.to_string());
564	
565	    // Main event loop.
566	    let result = run_loop(&mut term, &mut state, &event_rx, &cmd_tx);
567	
568	    // Cleanup: always restore terminal.
569	    let _ = cmd_tx.send(WsCommand::Quit);
570	    terminal::disable_raw_mode()?;
571	    crossterm::execute!(
572	        term.backend_mut(),
573	        terminal::LeaveAlternateScreen,
574	        crossterm::cursor::Show
575	    )?;
576	
577	    // Wait for ws thread to finish (with timeout).
578	    let _ = ws_handle.join();
579	
580	    result
581	}
