583	fn run_loop(
584	    term: &mut ratatui::Terminal<ratatui::backend::CrosstermBackend<io::Stdout>>,
585	    state: &mut AppState,
586	    event_rx: &mpsc::Receiver<ChatStreamEvent>,
587	    cmd_tx: &mpsc::Sender<WsCommand>,
588	) -> Result<()> {
589	    loop {
590	        term.draw(|f| draw(f, state))?;
591	
592	        // Drain all pending WebSocket events.
593	        while let Ok(evt) = event_rx.try_recv() {
594	            process_ws_event(state, evt);
595	        }
596	
597	        // Poll crossterm events with 50ms timeout for responsiveness.
598	        if event::poll(Duration::from_millis(50))?
599	            && let Event::Key(key) = event::read()?
600	        {
601	            match key.code {
602	                KeyCode::Esc => {
603	                    state.should_quit = true;
604	                }
605	                KeyCode::Char('c') if key.modifiers.contains(KeyModifiers::CONTROL) => {
606	                    state.should_quit = true;
607	                }
608	                KeyCode::Enter => {
609	                    let text = state.input.trim().to_string();
610	                    if !text.is_empty() {
611	                        state.push_user(&text);
612	                        state.input.clear();
613	
614	                        let mut msg = serde_json::json!({
615	                            "message": text,
616	                        });
617	                        if let Some(ref aid) = state.agent_id {
618	                            msg["agent_id"] = serde_json::json!(aid);
619	                        }
620	                        if let Some(ref p) = state.project {
621	                            msg["project"] = serde_json::json!(p);
622	                        }
623	                        let _ = cmd_tx.send(WsCommand::Send(msg.to_string()));
624	                    }
625	                }
626	                KeyCode::Backspace => {
627	                    state.input.pop();
628	                }
629	                KeyCode::Char(c) => {
630	                    state.input.push(c);
631	                }
632	                _ => {}
633	            }
634	        }
635	
636	        if state.should_quit {
637	            break;
638	        }
639	    }
640	
641	    Ok(())
642	}

