548	    terminal::enable_raw_mode()?;
549	    let mut stdout = io::stdout();
550	    crossterm::execute!(
551	        stdout,
552	        terminal::EnterAlternateScreen,
553	        crossterm::cursor::Hide
554	    )?;
555	
