// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

fn format_number(n: u32) -> String {
    let s = n.to_string();
    let mut result = String::new();
    for (i, c) in s.chars().rev().enumerate() {
        if i > 0 && i % 3 == 0 {
            result.push(',');
        }
        result.push(c);
    }
    result.chars().rev().collect()
}

// ---------------------------------------------------------------------------
// Slash commands
// ---------------------------------------------------------------------------

fn handle_slash_command(input: &str, state: &mut AppState, cmd_tx: &mpsc::Sender<WsCommand>) -> bool {
    let parts: Vec<&str> = input.trim_start_matches('/').splitn(2, ' ').collect();
    let cmd = parts[0].to_lowercase();
    let args = parts.get(1).copied().unwrap_or("");

    match cmd.as_str() {
        "exit" | "quit" => {
            state.should_quit = true;
            return true;
        }
        "new" => {
            state.messages.clear();
            state.status_text.clear();
            return true;
        }
        "model" => {
            if !args.is_empty() {
                let msg = serde_json::json!({
                    "message": format!("/model {}", args),
                });
                let _ = cmd_tx.send(WsCommand::Send(msg.to_string()));
            }
            return true;
        }
        "compress" => {
            let msg = serde_json::json!({
                "message": "/compress",
            });
            let _ = cmd_tx.send(WsCommand::Send(msg.to_string()));
            return true;
        }
        "status" => {
            let msg = serde_json::json!({
                "message": "/status",
            });
            let _ = cmd_tx.send(WsCommand::Send(msg.to_string()));
            return true;
        }
        "skills" => {
            let msg = serde_json::json!({
                "message": "/skills",
            });
            let _ = cmd_tx.send(WsCommand::Send(msg.to_string()));
            return true;
        }
        "help" => {
            state.push_system(
                "Slash commands: /new, /model <name>, /compress, /status, /skills, /exit".to_string(),
                Style::default().fg(Color::Cyan),
            );
            return true;
        }
        _ => {
            state.push_system(
                format!("Unknown command: /{}", cmd),
                Style::default().fg(Color::Red),
            );
            return true;
        }
    }
}

