502	fn render_markdown(text: &str, highlighter: &SyntaxHighlighter) -> Vec<Line> {
503	    let mut lines = Vec::new();
504	    let mut current_style = Style::default();
505	    let mut in_code_block = false;
506	    let mut code_content = String::new();
507	    let mut code_lang: Option<String> = None;
508	
509	    let opts = Options::empty();
510	    let parser = Parser::new_ext(text, opts);
511	
512	    for event in parser {
513	        match event {
514	            pulldown_cmark::Event::Start(tag) => match tag {
515	                pulldown_cmark::Tag::Paragraph => {}
516	                pulldown_cmark::Tag::Heading(level, _, _) => {
517	                    let prefix = match level {
518	                        pulldown_cmark::HeadingLevel::H1 => "# ",
519	                        pulldown_cmark::HeadingLevel::H2 => "## ",
520	                        pulldown_cmark::HeadingLevel::H3 => "### ",
521	                        pulldown_cmark::HeadingLevel::H4 => "#### ",
522	                        pulldown_cmark::HeadingLevel::H5 => "##### ",
523	                        pulldown_cmark::HeadingLevel::H6 => "###### ",
524	                    };
525	                    lines.push(Line::from(Span::styled(
526	                        prefix.to_string(),
527	                        Style::default().fg(Color::Yellow).add_modifier(Modifier::BOLD),
528	                    )));
529	                    current_style = Style::default().fg(Color::Yellow).add_modifier(Modifier::BOLD);
530	                }
531	                pulldown_cmark::Tag::BlockQuote => {
532	                    lines.push(Line::from(Span::styled(
533	                        "> ".to_string(),
534	                        Style::default().fg(Color::DarkGray),
535	                    )));
536	                    current_style = Style::default().fg(Color::DarkGray);
537	                }
538	                pulldown_cmark::Tag::CodeBlock(kind) => {
539	                    in_code_block = true;
540	                    code_content.clear();
541	                    if let pulldown_cmark::CodeBlockKind::Fenced(lang) = kind {
542	                        code_lang = Some(lang.to_string());
543	                    } else {
544	                        code_lang = None;
545	                    }
546	                }
547	                pulldown_cmark::Tag::List(_) => {}
548	                pulldown_cmark::Tag::Item => {
549	                    lines.push(Line::from(Span::styled(
550	                        "  • ".to_string(),
551	                        Style::default().fg(Color::Cyan),
552	                    )));
553	                    current_style = Style::default();
554	                }
555	                pulldown_cmark::Tag::Emphasis => {
556	                    current_style = current_style.add_modifier(Modifier::ITALIC);
557	                }
558	                pulldown_cmark::Tag::Strong => {
559	                    current_style = current_style.add_modifier(Modifier::BOLD);
560	                }
561	                pulldown_cmark::Tag::Link(_link_type, _dest, _title) => {
562	                    current_style = current_style.fg(Color::Blue).add_modifier(Modifier::UNDERLINED);
563	                }
564	                pulldown_cmark::Tag::Image(_link_type, _dest, _title) => {
565	                    current_style = current_style.fg(Color::Magenta);
566	                }
567	                pulldown_cmark::Tag::Table(_) => {}
568	                pulldown_cmark::Tag::TableHead => {}
569	                pulldown_cmark::Tag::TableRow => {}
570	                pulldown_cmark::Tag::TableCell => {}
571	            },
572	            pulldown_cmark::Event::End(tag) => match tag {
573	                pulldown_cmark::Tag::Paragraph => {
574	                    lines.push(Line::from(""));
575	                }
576	                pulldown_cmark::Tag::Heading(_, _, _) => {
577	                    lines.push(Line::from(""));
578	                    current_style = Style::default();
579	                }
580	                pulldown_cmark::Tag::BlockQuote => {
581	                    lines.push(Line::from(""));
582	                }
583	                pulldown_cmark::Tag::CodeBlock(_) => {
584	                    in_code_block = false;
585	                    if !code_content.is_empty() {
586	                        // Render code block with syntax highlighting.
587	                        for (line, style) in highlighter.highlight_code(&code_content, code_lang.as_deref()) {
588	                            lines.push(Line::from(Span::styled(line, style)));
589	                        }
590	                        lines.push(Line::from(""));
591	                    }
592	                    code_content.clear();
593	                    code_lang = None;
594	                    current_style = Style::default();
595	                }
596	                pulldown_cmark::Tag::List(_) => {}
597	                pulldown_cmark::Tag::Item => {
598	                    current_style = Style::default();
599	                }
600	                pulldown_cmark::Tag::Emphasis => {
601	                    current_style = current_style.remove_modifier(Modifier::ITALIC);
602	                }
603	                pulldown_cmark::Tag::Strong => {
604	                    current_style = current_style.remove_modifier(Modifier::BOLD);
605	                }
606	                pulldown_cmark::Tag::Link(_, _, _) => {
607	                    current_style = current_style.remove_modifier(Modifier::UNDERLINED);
608	                }
609	                pulldown_cmark::Tag::Image(_, _, _) => {
610	                    current_style = Style::default();
611	                }
612	                pulldown_cmark::Tag::Table(_) => {}
613	                pulldown_cmark::Tag::TableHead => {}
614	                pulldown_cmark::Tag::TableRow => {}
615	                pulldown_cmark::Tag::TableCell => {}
616	            },
617	            pulldown_cmark::Event::Text(text) => {
618	                if in_code_block {
619	                    code_content.push_str(&text);
620	                } else {
621	                    for ch in text.chars() {
622	                        if ch == '\n' {
623	                            lines.push(Line::from(""));
624	                        } else {
625	                            // Accumulate characters into the current line.
626	                            if lines.is_empty() {
627	                                lines.push(Line::from(Span::styled(ch.to_string(), current_style)));
628	                            } else {
629	                                let last = lines.last_mut().unwrap();
630	                                last.spans.last_mut().unwrap().content.push(ch);
631	                            }
632	                        }
633	                    }
634	                }
635	            }
636	            pulldown_cmark::Event::Code(text) => {
637	                let span = Span::styled(
638	                    text.to_string(),
639	                    Style::default().fg(Color::LightYellow).add_modifier(Modifier::BOLD),
640	                );
641	                if lines.is_empty() {
642	                    lines.push(Line::from(span));
643	                } else {
644	                    lines.last_mut().unwrap().spans.push(span);
645	                }
646	            }
647	            pulldown_cmark::Event::Html(_html) => {}
648	            pulldown_cmark::Event::SoftBreak => {
649	                lines.push(Line::from(""));
650	            }
651	            pulldown_cmark::Event::HardBreak => {
652	                lines.push(Line::from(""));
653	            }
654	            pulldown_cmark::Event::Rule => {
655	                for _ in 0..2 {
656	                    lines.push(Line::from(Span::styled(
657	                        "─".repeat(80),
658	                        Style::default().fg(Color::DarkGray),
659	                    )));
660	                }
661	            }
662	            pulldown_cmark::Event::FootnoteReference(_name) => {}
663	            pulldown_cmark::Event::TaskListMarker(true) => {
664	                if let Some(last) = lines.last_mut() {
665	                    let check = Span::styled("[x] ", Style::default().fg(Color::Green));
666	                    last.spans.push(check);
667	                }
668	            }
669	            pulldown_cmark::Event::TaskListMarker(false) => {
670	                if let Some(last) = lines.last_mut() {
671	                    let check = Span::styled("[ ] ", Style::default().fg(Color::DarkGray));
672	                    last.spans.push(check);
673	                }
674	            }
675	        }
676	    }
677	
678	    // Clean up empty trailing lines.
679	    while lines.last().map(|l| l.spans.is_empty() && l.is_empty()) == Some(true) {
680	        lines.pop();
681	    }
682	
683	    lines
684	}
