690	/// Terminal chat interface using ratatui + crossterm + tungstenite.
691	pub(crate) async fn cmd_chat_tui(
692	    config_path: &Option<PathBuf>,
693	    agent_name: Option<&str>,
694	    project: Option<&str>,
695	) -> Result<()> {
696	    let (config, _) = load_config(config_path)?;
697	    let data_dir = config.data_dir();
698	
699	    // Resolve the persistent agent to chat with.
700	    let registry = sigil_orchestrator::agent_registry::AgentRegistry::open(&data_dir)?;
701	    let agent = if let Some(name) = agent_name {
702	        registry.get_active_by_name(name).await?
703	    } else {
704	        registry.default_for_project(project).await?
705	    };
706	
707	    let (agent_display, agent_id) = match &agent {
708	        Some(a) => (
709	            a.display_name.as_deref().unwrap_or(&a.name).to_string(),
710	            Some(a.id.clone()),
711	        ),
712	        None => (
713	            config
714	                .leader_agent()
715	                .map(|a| a.name.clone())
716	                .unwrap_or_else(|| "Rei".into()),
717	            None,
718	        ),
719	    };
720	
721	    // Extract port from the bind address (e.g. "0.0.0.0:8400" -> 8400).
722	    let bind = &config.web.bind;
723	    let port = bind
724	        .rsplit(':')
725	        .next()
726	        .and_then(|p| p.parse::<u16>().ok())
727	        .unwrap_or(8400);
728	    let ws_url = format!("ws://127.0.0.1:{port}/api/chat/stream");
729	
730	    // Channels: ws events -> main thread, main thread -> ws commands.
731	    let (event_tx, event_rx) = mpsc::channel::<ChatStreamEvent>();
732	    let (cmd_tx, cmd_rx) = mpsc::channel::<WsCommand>();
733	
734	    let ws_handle = spawn_ws_thread(ws_url, cmd_rx, event_tx);
735	
736	    // Enter terminal raw mode.
737	    terminal::enable_raw_mode()?;
738	    let mut stdout = io::stdout();
739	    crossterm::execute!(
740	        stdout,
741	        terminal::EnterAlternateScreen,
742	        crossterm::cursor::Hide
743	    )?;
744	
745	    let backend = ratatui::backend::CrosstermBackend::new(stdout);
746	    let mut term = ratatui::Terminal::new(backend)?;
747	
748	    let mut state = AppState::new();
749	    state.status_agent = agent_display;
750	    // Store agent_id and project in state for inclusion in WebSocket messages.
751	    state.agent_id = agent_id;
752	    state.project = project.map(|s| s.to_string());
753	
754	    // Main event loop.
755	    let result = run_loop(&mut term, &mut state, &event_rx, &cmd_tx);
756	
757	    // Cleanup: always restore terminal.
758	    let _ = cmd_tx.send(WsCommand::Quit);
759	    terminal::disable_raw_mode()?;
760	    crossterm::execute!(
761	        term.backend_mut(),
762	        terminal::LeaveAlternateScreen,
763	        crossterm::cursor::Show
764	    )?;
765	
766	    // Wait for ws thread to finish (with timeout).
767	    let _ = ws_handle.join();
768	
769	    result
770	}
