                        let _ = cmd_tx.send(WsCommand::Send(msg.to_string()));
                    }
                }
                KeyCode::Backspace => {
                    state.input.pop();
                }
                KeyCode::Char(c) => {
                    state.input.push(c);
                }
                _ => {}
            }
        }

        if state.should_quit {
            break;
        }
    }

    Ok(())
}

